38→export function createSheetViewport(sourceView = 'plan', sourceFloorId = null, options = {}) {
39→  const defaultRole = sourceView === '3d_preview'
40→    ? 'supplemental'
41→    : (sourceView === 'plan' ? 'primary' : 'secondary');
42→
43→  return {
44→    id: generateId('viewport'),
45→    sourceView,
46→    sourceFloorId,
47→    sourceRefId: options.sourceRefId ?? null,
48→    x: options.x ?? 20,
49→    y: options.y ?? 20,
50→    width: options.width ?? 160,
51→    height: options.height ?? 100,
52→    scale: options.scale ?? 100,
53→    title: options.title ?? '',
54→    rotation: options.rotation ?? 0,
55→    role: options.role ?? defaultRole,
56→    captionPosition: options.captionPosition ?? 'below',
57→    referenceNote: options.referenceNote ?? '',
58→    lockAutoLayout: options.lockAutoLayout ?? false,
59→  };
60→}
