  3→function CellText({ x, y, label, value, valueFontSize = 3.2, strong = false }) {
  4→  return (
  5→    <>
  6→      <text
  7→        x={x}
  8→        y={y}
  9→        fontSize={1.8}
 10→        fill={SHEET_COLORS.textMuted}
 11→        letterSpacing={0.28}
 12→      >
 13→        {label}
 14→      </text>
 15→      <text
 16→        x={x}
 17→        y={y + (strong ? 4.3 : 3.6)}
 18→        fontSize={valueFontSize}
 19→        fill={SHEET_COLORS.text}
 20→        fontWeight={strong ? 600 : 500}
 21→      >
 22→        {value}
 23→      </text>
 24→    </>
 25→  );
 26→}
 27→
 28→function MetadataRow({ row }) {
 29→  return (
 30→    <g>
 31→      <rect
 32→        x={row.x}
 33→        y={row.y}
 34→        width={row.width}
 35→        height={row.height}
 36→        fill="none"
 37→        stroke={SHEET_COLORS.border}
 38→        strokeWidth={0.3}
 39→      />
 40→      <line
 41→        x1={row.x + row.labelWidth}
 42→        y1={row.y}
 43→        x2={row.x + row.labelWidth}
 44→        y2={row.y + row.height}
 45→        stroke={SHEET_COLORS.border}
 46→        strokeWidth={0.25}
 47→      />
 48→      <text
 49→        x={row.x + 1.5}
 50→        y={row.y + row.height * 0.62}
 51→        fontSize={1.8}
 52→        fill={SHEET_COLORS.textMuted}
 53→        letterSpacing={0.2}
 54→      >
 55→        {row.label}
 56→      </text>
 57→      <text
 58→        x={row.x + row.labelWidth + 1.6}
 59→        y={row.y + row.height * 0.62}
 60→        fontSize={2.6}
 61→        fill={SHEET_COLORS.text}
 62→        fontWeight={500}
 63→      >
 64→        {row.value}
 65→      </text>
 66→    </g>
 67→  );
 68→}
