 70→function RevisionBlock({ revisions }) {
 71→  const columnX = revisions.x + 10;
 72→  const rowHeight = (revisions.height - revisions.headerHeight) / 4;
 73→  const rows = [...revisions.rows];
 74→  while (rows.length < 4) {
 75→    rows.push({ id: `blank-${rows.length}`, code: '', date: '', description: '' });
 76→  }
 77→
 78→  return (
 79→    <g>
 80→      <rect
 81→        x={revisions.x}
 82→        y={revisions.y}
 83→        width={revisions.width}
 84→        height={revisions.height}
 85→        fill="none"
 86→        stroke={SHEET_COLORS.border}
 87→        strokeWidth={0.35}
 88→      />
 89→      <rect
 90→        x={revisions.x}
 91→        y={revisions.y}
 92→        width={revisions.width}
 93→        height={revisions.headerHeight}
 94→        fill={SHEET_COLORS.panelFill}
 95→        stroke={SHEET_COLORS.border}
 96→        strokeWidth={0.3}
 97→      />
 98→      <line
 99→        x1={columnX}
100→        y1={revisions.y}
101→        x2={columnX}
102→        y2={revisions.y + revisions.height}
103→        stroke={SHEET_COLORS.border}
104→        strokeWidth={0.25}
105→      />
106→      <line
107→        x1={columnX + 15}
108→        y1={revisions.y}
109→        x2={columnX + 15}
110→        y2={revisions.y + revisions.height}
111→        stroke={SHEET_COLORS.border}
112→        strokeWidth={0.25}
113→      />
114→      <text
115→        x={revisions.x + 1.6}
116→        y={revisions.y + revisions.headerHeight * 0.62}
117→        fontSize={1.8}
118→        fill={SHEET_COLORS.textMuted}
119→        letterSpacing={0.2}
120→      >
121→        REV
122→      </text>
123→      <text
124→        x={columnX + 1.5}
125→        y={revisions.y + revisions.headerHeight * 0.62}
126→        fontSize={1.8}
127→        fill={SHEET_COLORS.textMuted}
128→        letterSpacing={0.2}
129→      >
130→        DATE
131→      </text>
132→      <text
133→        x={columnX + 16.5}
134→        y={revisions.y + revisions.headerHeight * 0.62}
135→        fontSize={1.8}
136→        fill={SHEET_COLORS.textMuted}
137→        letterSpacing={0.2}
138→      >
139→        DESCRIPTION
140→      </text>
141→      {rows.map((revision, index) => {
142→        const y = revisions.y + revisions.headerHeight + rowHeight * index;
143→        return (
144→          <g key={revision.id}>
145→            <line
146→              x1={revisions.x}
147→              y1={y}
148→              x2={revisions.x + revisions.width}
149→              y2={y}
150→              stroke={SHEET_COLORS.border}
151→              strokeWidth={0.22}
152→            />
153→            <text x={revisions.x + 1.8} y={y + rowHeight * 0.62} fontSize={2.1} fill={SHEET_COLORS.text}>
154→              {revision.code}
155→            </text>
156→            <text x={columnX + 1.6} y={y + rowHeight * 0.62} fontSize={1.9} fill={SHEET_COLORS.textMuted}>
157→              {revision.date}
158→            </text>
159→            <text x={columnX + 16.5} y={y + rowHeight * 0.62} fontSize={1.9} fill={SHEET_COLORS.text}>
160→              {revision.description}
161→            </text>
162→          </g>
163→        );
164→      })}
165→    </g>
166→  );
167→}
